def solve(pattern, s):
    d, used = {}, set()
    def backtrack(p_idx, s_idx):
        if p_idx == len(pattern) and s_idx == len(s): return True
        if p_idx == len(pattern) or s_idx == len(s): return False
        c = pattern[p_idx]
        if c in d:
            w = d[c]
            if s.startswith(w, s_idx):
                return backtrack(p_idx + 1, s_idx + len(w))
            return False
        for end in range(s_idx + 1, len(s) + 1):
            w = s[s_idx:end]
            if w not in used:
                d[c] = w
                used.add(w)
                if backtrack(p_idx + 1, end): return True
                del d[c]
                used.remove(w)
        return False
    return str(backtrack(0, 0)).lower()

